4	\chapter{Algebraic Iwasawa Comparison}
5	\label{chap:algebraic-comparison}
6	
7	% archon:covers MR4372220OnTheAnticyclotomicIwasawaTheoryOfRationalEllipticCurvesAtEisensteinPrimes/Algebraic.lean
8	
9	This chapter isolates the algebraic comparison lane. The local Selmer formalism is taken as given: here we only compare the residual decomposition
10	\[
11	E[p]^{ss}\cong \mathbb F_p(\phi)\oplus \mathbb F_p(\psi)
12	\]
13	with the corresponding character Selmer groups, and we record the local Euler-factor bookkeeping that produces the \(\lambda\)-formula for \(\mathfrak X_E\).
14	
15	Throughout, we write
16	\[
17	\mathfrak X_E^S:=\rH^1_{\Fcal_{\rm Gr}^S}(K,M_E)^\vee,
18	\qquad
19	\mathfrak X_E:=\rH^1_{\Fcal_{\rm Gr}}(K,M_E)^\vee,
20	\]
21	and for each split prime \(w\nmid p\) in \(S\) we use
22	\[
23	\mathcal P_w(E)=P_w(\ell^{-1}\gamma_w)\in\Lambda
24	\]
25	for the local Euler factor of \(E\). The character-side modules and Euler factors are supplied by the local Selmer chapter.
26	
27	\section{Residual comparison}
28	
29	\begin{proposition}[Residual comparison for \(E[p]\)]
30	  \label{prop:modp-E}
31	  \lean{MR4372220.Algebraic.residualComparison}
32	  % SOURCE: [MR4372220], Prop.~\ref{cormodp}, §Algebraic side, Selmer groups of E (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
33	  % SOURCE QUOTE: "0 \rightarrow \rH^1_{\Fcal_{\rm Gr}^S}(K,M_\phi[p]) \rightarrow \rH^1_{\Fcal_{\rm Gr}^S}(K,M_E[p]) \rightarrow"
34	  \textit{Source: MR4372220, Selmer groups of E.}
35	  The short exact sequence \(0 \to M_\phi[p] \to M_E[p] \to M_\psi[p] \to 0\) induces a natural exact sequence
36	  \[
37	  0 \to \rH^1_{\Fcal_{\rm Gr}^S}(K,M_\phi[p]) \to \rH^1_{\Fcal_{\rm Gr}^S}(K,M_E[p]) \to
38	  \rH^1_{\Fcal_{\rm Gr}^S}(K,M_\psi[p]) \to 0.
39	  \]
40	  In particular, the imprimitive residual Selmer group of \(E\) is finite, and its \(\mathbb F_p\)-dimension is the sum of the corresponding character dimensions.
41	\end{proposition}
42	
43	\begin{proof}
44	The restriction diagram at \(\bar v\) has exact rows for \(\phi\), \(\psi\), and \(E\). Applying the snake lemma gives the exact sequence on \(S\)-imprimitive residual Selmer groups. The finiteness and dimension statement follows by adding the character-side residual dimensions.
45	\end{proof}
46	
47	\begin{proposition}[Torsion and \(\mu=0\) for \(E\)]
48	  \label{prop:modp-E-tors}
49	  \lean{MR4372220.Algebraic.muZeroE}
50	  \uses{prop:modp-E}
51	  % SOURCE: [MR4372220], Prop.~\ref{propmodp}, §Algebraic side, Selmer groups of E (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
52	  % SOURCE QUOTE: "the modules \mathfrak{X}_E^S and \mathfrak{X}_E are both \Lambda-torsion with \mu=0"
53	  \textit{Source: MR4372220, Selmer groups of E.}
54	  The natural map
55	  \[
56	  \rH^1_{\Fcal_{\rm Gr}^S}(K,M_E[p]) \simeq \rH^1_{\Fcal_{\rm Gr}^S}(K,M_E)[p]
57	  \]
58	  identifies the residual and \(p\)-torsion Selmer groups. Consequently, \(\mathfrak X_E^S\) and \(\mathfrak X_E\) are \(\Lambda\)-torsion, and both have \(\mu\)-invariant zero.
59	\end{proposition}
60	
61	\begin{proof}
62	The assumption on \(\phi|_{G_p}\) forces \(E(K_{\bar v})[p]=0\), so the local \(p\)-torsion comparison at \(\bar v\) is an isomorphism. The finiteness of the residual group then implies \(\mu=0\) for \(\mathfrak X_E^S\), and the quotient map \(\mathfrak X_E^S \twoheadrightarrow \mathfrak X_E\) gives the same conclusion for \(\mathfrak X_E\).
63	\end{proof}
64	
65	\begin{corollary}[No finite submodules]
66	  \label{cor:lambda-E}
67	  \lean{MR4372220.Algebraic.lambdaE}
68	  \uses{prop:modp-E-tors}
69	  % SOURCE: [MR4372220], Cor.~\ref{prop426}, §Algebraic side, Selmer groups of E (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
70	  % SOURCE QUOTE: "\mathfrak{X}_E^S has no non-trivial finite \Lambda-submodules"
71	  \textit{Source: MR4372220, Selmer groups of E.}
72	  The module \(\mathfrak X_E^S\) has no non-trivial finite \(\Lambda\)-submodules, and
73	  \[
74	  \lambda(\mathfrak X_E^S)=\dim_{\mathbb F_p}\rH^1_{\Fcal_{\rm Gr}^S}(K,M_E[p]).
75	  \]
76	\end{corollary}
77	
78	\begin{proof}
79	The dual local cohomology at \(\bar v\) is \(\Lambda\)-cofree, so the standard Greenberg quotient argument removes finite submodules. Combined with the identification of residual and \(p\)-torsion Selmer groups from the previous proposition, this gives the \(\lambda\)-dimension formula.
80	\end{proof}
81	
82	\section{Algebraic comparison theorem}
83	
84	\begin{theorem}[Algebraic Iwasawa comparison]
85	  \label{MAINalgside}
86	  \lean{MR4372220.Algebraic.mainAlgSide}
87	  \uses{prop:modp-E-tors, cor:lambda-E}
88	  % SOURCE: [MR4372220], Thm.~\ref{MAINalgside}, §Algebraic side, Comparison I: Algebraic Iwasawa invariants (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
89	  % SOURCE QUOTE: "\mathfrak{X}_E is \Lambda-torsion with \mu(\mathfrak{X}_E)=0"
90	  \textit{Source: MR4372220, Comparison I: Algebraic Iwasawa invariants.}
91	  Assume that \(\phi|_{G_p}\neq \mathds{1},\omega\). Then \(\mathfrak X_E\) is \(\Lambda\)-torsion with \(\mu(\mathfrak X_E)=0\), and
92	  \[
93	  \lambda(\mathfrak X_E)=\lambda(\mathfrak X_\phi)+\lambda(\mathfrak X_\psi)
94	  +\sum_{w\in S}\Bigl(\lambda(\mathcal P_w(\phi))+\lambda(\mathcal P_w(\psi))-\lambda(\mathcal P_w(E))\Bigr).
95	  \]
96	\end{theorem}
97	
98	\begin{proof}
99	The torsion and \(\mu\)-vanishing part is already supplied by Proposition~\ref{prop:modp-E-tors}. For the \(\lambda\)-invariant, the corollary gives the residual comparison on the \(E\)-side, while the character-side formula supplies the corresponding identity for \(\mathfrak X_\phi\) and \(\mathfrak X_\psi\). The only remaining step is to subtract the local split-prime Euler factors, whose \(E\)-contribution is \(\mathcal P_w(E)\) and whose character contributions are \(\mathcal P_w(\phi)\) and \(\mathcal P_w(\psi)\).
100	\end{proof}
